"use client"

import { useState } from "react"
import { MessageCircle, X, Play } from "lucide-react"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { cn } from "@/lib/utils"

export function FloatingElements() {
  const [chatOpen, setChatOpen] = useState(false)
  const [videoOpen, setVideoOpen] = useState(false)
  const [message, setMessage] = useState("")

  return (
    <>
      {/* Flash Video Corner */}
      <div
        className={cn(
          "fixed bottom-24 right-4 z-40 transition-all duration-300",
          videoOpen ? "w-72 h-40" : "w-16 h-16",
        )}
      >
        {videoOpen ? (
          <div className="relative w-full h-full bg-foreground rounded-lg overflow-hidden shadow-lg">
            <div className="absolute inset-0 flex items-center justify-center bg-primary/20">
              <Play className="h-8 w-8 text-primary-foreground" />
              <span className="text-primary-foreground text-sm ml-2">Fresh Catch Today!</span>
            </div>
            <Button
              size="icon"
              variant="ghost"
              className="absolute top-1 right-1 h-6 w-6 bg-background/20 hover:bg-background/40"
              onClick={() => setVideoOpen(false)}
            >
              <X className="h-4 w-4 text-primary-foreground" />
            </Button>
          </div>
        ) : (
          <Button
            size="icon"
            className="w-16 h-16 rounded-full bg-accent hover:bg-accent/90 shadow-lg"
            onClick={() => setVideoOpen(true)}
          >
            <Play className="h-6 w-6" />
          </Button>
        )}
      </div>

      {/* Live Chat Button */}
      <div className="fixed bottom-4 right-4 z-40">
        {chatOpen ? (
          <div className="w-80 h-96 bg-card rounded-lg shadow-xl border border-border overflow-hidden flex flex-col">
            {/* Chat Header */}
            <div className="bg-primary text-primary-foreground p-4 flex items-center justify-between">
              <div>
                <h3 className="font-semibold">Chat with us</h3>
                <p className="text-xs text-primary-foreground/80">We typically reply in minutes</p>
              </div>
              <Button
                size="icon"
                variant="ghost"
                className="h-8 w-8 hover:bg-primary-foreground/20"
                onClick={() => setChatOpen(false)}
              >
                <X className="h-4 w-4" />
              </Button>
            </div>

            {/* Chat Messages */}
            <div className="flex-1 p-4 overflow-y-auto bg-secondary/50">
              <div className="bg-card p-3 rounded-lg max-w-[80%] shadow-sm">
                <p className="text-sm">Hi! How can we help you today?</p>
                <span className="text-xs text-muted-foreground">Just now</span>
              </div>
            </div>

            {/* Chat Input */}
            <div className="p-4 border-t border-border">
              <form
                onSubmit={(e) => {
                  e.preventDefault()
                  if (message.trim()) {
                    alert(`Message sent: ${message}`)
                    setMessage("")
                  }
                }}
                className="flex gap-2"
              >
                <Input
                  placeholder="Type a message..."
                  value={message}
                  onChange={(e) => setMessage(e.target.value)}
                  className="flex-1"
                />
                <Button type="submit" size="sm">
                  Send
                </Button>
              </form>
            </div>
          </div>
        ) : (
          <Button
            size="icon"
            className="w-14 h-14 rounded-full bg-primary hover:bg-primary/90 shadow-lg"
            onClick={() => setChatOpen(true)}
          >
            <MessageCircle className="h-6 w-6" />
          </Button>
        )}
      </div>
    </>
  )
}
